import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { FiUploadCloud, FiCheckCircle } from 'react-icons/fi';
import { uploadModelAnswer, evaluateAnswer, getAllStudents, createStudent } from '../services/api';
import './Evaluate.css';

const Evaluate = ({ setLoading }) => {
  const navigate = useNavigate();

  const [step, setStep] = useState(1);
  const [modelAnswerText, setModelAnswerText] = useState('');
  const [studentFile, setStudentFile] = useState(null);
  const [maxMarks, setMaxMarks] = useState('');
  const [question, setQuestion] = useState('');

  const [students, setStudents] = useState([]);
  const [selectedStudent, setSelectedStudent] = useState('');

  const [error, setError] = useState('');
  const [results, setResults] = useState(null);

  const [showNewStudent, setShowNewStudent] = useState(false);
  const [newStudent, setNewStudent] = useState({
    name: '',
    email: '',
    rollNumber: '',
    class: ''
  });

  useEffect(() => {
    loadStudents();
  }, []);

  const loadStudents = async () => {
    try {
      const res = await getAllStudents();
      setStudents(res.students || []);
    } catch (err) {
      console.error(err);
    }
  };

  // ================= MODEL ANSWER =================
  const handleModelAnswerUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setError('');
    setLoading(true, 'Extracting model answer...');

    try {
      const res = await uploadModelAnswer(file);
      setModelAnswerText(res.model_answer);
      setStep(2);
    } catch (err) {
      setError(err.response?.data?.error || err.message);
    } finally {
      setLoading(false);
    }
  };

  // ================= ADD STUDENT =================
  const handleAddStudent = async () => {
    if (!newStudent.name) {
      setError('Student name required');
      return;
    }

    try {
      const res = await createStudent(
        newStudent.name,
        newStudent.email,
        newStudent.rollNumber,
        newStudent.class
      );

      setStudents(prev => [...prev, res.student]);
      setSelectedStudent(res.student._id);

      setShowNewStudent(false);
      setNewStudent({ name: '', email: '', rollNumber: '', class: '' });
    } catch (err) {
      setError(err.response?.data?.error || err.message);
    }
  };

  // ================= EVALUATE =================
  const handleEvaluate = async () => {
    if (!studentFile) return setError('Upload student file');
    if (!maxMarks) return setError('Enter max marks');
    if (!selectedStudent) return setError('Select student');

    setError('');
    setLoading(true, 'Evaluating...');

    try {
      const formData = new FormData();

      formData.append('student_file', studentFile);
      formData.append('model_answer', modelAnswerText);
      formData.append('max_marks', maxMarks);
      formData.append('question', question);
      formData.append('student_id', selectedStudent); // ✅ only this needed

      const res = await evaluateAnswer(formData);

      const evaluation = res.evaluation || res;
      evaluation.max_marks = maxMarks;

      setResults(evaluation);

      navigate('/results/new', {
        state: { evaluation }
      });

    } catch (err) {
      setError(err.response?.data?.error || err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="evaluate">
      <div className="evaluate-container">

        <h1 className="page-title">Evaluate Answer</h1>

        {error && <div className="error-alert">{error}</div>}

        {/* ================= STEP 1 ================= */}
        {step === 1 && (
          <div className="step-content">
            <h2>Upload Model Answer</h2>

            <div className="upload-area">
              <input type="file" accept=".pdf" onChange={handleModelAnswerUpload} />
            </div>

            <textarea
              value={modelAnswerText}
              onChange={(e) => setModelAnswerText(e.target.value)}
              placeholder="Paste model answer..."
            />

            <button
              onClick={() => setStep(2)}
              disabled={!modelAnswerText}
              className="btn btn-primary"
            >
              Next →
            </button>
          </div>
        )}

        {/* ================= STEP 2 ================= */}
        {step === 2 && (
          <div className="step-content">

            <h2>Student Details</h2>

            {/* STUDENT SELECT */}
            <select
              value={selectedStudent}
              onChange={(e) => setSelectedStudent(e.target.value)}
              className="form-select"
            >
              <option value="">Select Student</option>
              {students.map(s => (
                <option key={s._id} value={s._id}>
                  {s.name} ({s.rollNumber})
                </option>
              ))}
            </select>

            {/* ADD STUDENT */}
            <button onClick={() => setShowNewStudent(!showNewStudent)}>
              + Add Student
            </button>

            {showNewStudent && (
              <div className="add-form">
                <input
                  placeholder="Name"
                  value={newStudent.name}
                  onChange={(e) => setNewStudent({ ...newStudent, name: e.target.value })}
                />
                <input
                  placeholder="Email"
                  value={newStudent.email}
                  onChange={(e) => setNewStudent({ ...newStudent, email: e.target.value })}
                />
                <input
                  placeholder="Roll Number"
                  value={newStudent.rollNumber}
                  onChange={(e) => setNewStudent({ ...newStudent, rollNumber: e.target.value })}
                />
                <input
                  placeholder="Class"
                  value={newStudent.class}
                  onChange={(e) => setNewStudent({ ...newStudent, class: e.target.value })}
                />

                <button onClick={handleAddStudent}>Save</button>
              </div>
            )}

            {/* FILE */}
            <input
              type="file"
              onChange={(e) => setStudentFile(e.target.files[0])}
            />

            {/* MARKS */}
            <input
              type="number"
              placeholder="Max Marks"
              value={maxMarks}
              onChange={(e) => setMaxMarks(e.target.value)}
            />

            {/* QUESTION */}
            <textarea
              placeholder="Question (optional)"
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
            />

            <button className="btn btn-primary" onClick={handleEvaluate}>
              Evaluate 🚀
            </button>
          </div>
        )}

      </div>
    </div>
  );
};

export default Evaluate;
